$ virsh --version 10.0.0 $ qemu-system-x86_64 --version QEMU emulator version 8.2.2 (Debian 1:8.2.2+ds-0ubuntu1.13) Copyright (c) 2003-2023 Fabrice Bellard and the QEMU Project developers $ virsh domxml-to-native qemu-argv macOS.xml LC_ALL=C PATH=/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/snap/bin USER=root HOME=/var/lib/libvirt/qemu/domain--1-macOS XDG_DATA_HOME=/var/lib/libvirt/qemu/domain--1-macOS/.local/share XDG_CACHE_HOME=/var/lib/libvirt/qemu/domain--1-macOS/.cache XDG_CONFIG_HOME=/var/lib/libvirt/qemu/domain--1-macOS/.config /usr/bin/qemu-system-x86_64 -name guest=macOS,debug-threads=on -S -object '{"qom-type":"secret","id":"masterKey0","format":"raw","file":"/var/lib/libvirt/qemu/domain--1-macOS/master-key.aes"}' -machine pc-q35-8.2,usb=off,dump-guest-core=off,memory-backend=pc.ram,hpet=off,acpi=on -accel kvm -cpu qemu64 -m size=67108864k -object '{"qom-type":"memory-backend-ram","id":"pc.ram","size":68719476736}' -overcommit mem-lock=off -smp 1,sockets=1,cores=1,threads=1 -uuid 3ba643ae-fe60-43f3-a67e-569a8fa7af8b -no-user-config -nodefaults -chardev socket,id=charmonitor,path=/var/lib/libvirt/qemu/domain--1-macOS/monitor.sock,server=on,wait=off -mon chardev=charmonitor,id=monitor,mode=control -rtc base=utc,driftfix=slew -global kvm-pit.lost_tick_policy=delay -no-shutdown -boot strict=on -device '{"driver":"ahci","id":"sata1","bus":"pcie.0","addr":"0xa"}' -blockdev '{"driver":"file","filename":"/home/mukai/Documents/OSX-KVM/OpenCore/OpenCore.qcow2","node-name":"libvirt-4-storage","auto-read-only":true,"discard":"unmap"}' -blockdev '{"node-name":"libvirt-4-format","read-only":false,"driver":"qcow2","file":"libvirt-4-storage"}' -device '{"driver":"ide-hd","bus":"sata1.2","drive":"libvirt-4-format","id":"sata1-0-2","bootindex":1}' -blockdev '{"driver":"file","filename":"/home/mukai/Documents/OSX-KVM/BaseSystem.qcow2","node-name":"libvirt-3-storage","auto-read-only":true,"discard":"unmap"}' -blockdev '{"node-name":"libvirt-3-format","read-only":false,"driver":"qcow2","file":"libvirt-3-storage"}' -device '{"driver":"ide-hd","bus":"sata1.3","drive":"libvirt-3-format","id":"sata1-0-3"}' -blockdev '{"driver":"file","filename":"/home/mukai/Documents/OSX-KVM/mac_hdd_ng.img","node-name":"libvirt-2-storage","auto-read-only":true,"discard":"unmap"}' -blockdev '{"node-name":"libvirt-2-format","read-only":false,"driver":"qcow2","file":"libvirt-2-storage"}' -device '{"driver":"ide-hd","bus":"sata1.4","drive":"libvirt-2-format","id":"sata1-0-4"}' -blockdev '{"driver":"file","filename":"/home/mukai/Documents/OSX-KVM/InstallAssistant.qcow2","node-name":"libvirt-1-storage","auto-read-only":true,"discard":"unmap"}' -blockdev '{"node-name":"libvirt-1-format","read-only":false,"driver":"qcow2","file":"libvirt-1-storage"}' -device '{"driver":"ide-hd","bus":"sata1.5","drive":"libvirt-1-format","id":"sata1-0-5"}' -audiodev '{"id":"audio1","driver":"spice"}' -spice port=5901,addr=127.0.0.1,disable-ticketing=on,seamless-migration=on -global ICH9-LPC.noreboot=off -watchdog-action reset -drive if=pflash,format=raw,readonly=on,file=/home/mukai/Documents/OSX-KVM/OVMF_CODE_4M.fd -drive if=pflash,format=raw,file=/home/mukai/Documents/OSX-KVM/OVMF_VARS-1920x1080.fd -cpu Skylake-Client,-hle,-rtm,kvm=on,vendor=GenuineIntel,+invtsc,vmware-cpuid-freq=on,+ssse3,+sse4.2,+popcnt,+avx,+aes,+xsave,+xsaveopt,check -smp 12,cores=2,sockets=3,threads=2,maxcpus=12 -device qemu-xhci,id=xhci -device usb-kbd,bus=xhci.0 -device usb-tablet,bus=xhci.0 -device usb-ehci,id=ehci -device 'isa-applesmc,osk=ourhardworkbythesewordsguardedpleasedontsteal(c)AppleComputerInc' -smbios type=2 -device ich9-intel-hda -device hda-duplex,audiodev=audio1 -device vmware-svga -sandbox on,obsolete=deny,elevateprivileges=deny,spawn=deny,resourcecontrol=deny -msg timestamp=on
Apart from libvirt's standard management options (monitor socket, sandbox, SPICE, etc.), the generated command line is identical to OpenCore-Boot.sh.
The only caveat is that libvirt prepends its own -cpu and -smp, which are then overwritten by the qemu:commandline values. As shown below, QEMU simply takes the last declaration for both options:
$ curl -sL "https://gitlab.com/qemu-project/qemu/-/raw/v8.2.2/system/vl.c" | sed -n '2829,2832s/^ \{12\}//p' case QEMU_OPTION_cpu: /* hw initialization will check this */ cpu_option = optarg; break;
$ curl -sL "https://gitlab.com/qemu-project/qemu/-/raw/v8.2.2/system/vl.c" | sed -n '3364,3366s/^ \{12\}//p' case QEMU_OPTION_smp: machine_parse_property_opt(qemu_find_opts("smp-opts"), "smp", optarg);
machine_parse_property_opt calls machine_merge_property (line 1575-1586), which calls keyval_merge to merge the dict, overwriting earlier values.
